+    #[test]
+    fn results_focus_persists_through_theme_and_filter_changes() {
+        let mut app = app_with_hits(10);
+        let _ = app.update(CassMsg::FocusToggled);
+        assert_eq!(
+            app.focused_region(),
+            FocusRegion::Detail,
+            "precondition: focus should be detail"
